  1	import {
  2	  type ForwardedRef,
  3	  forwardRef,
  4	  type MutableRefObject,
  5	  useImperativeHandle,
  6	  useMemo,
  7	  useRef,
  8	  useState,
  9	} from 'react';
 10	
 11	import {
 12	  MenuToggle,
 13	  type MenuToggleStatus,
 14	  Select as PfSelect,
 15	  SelectList,
 16	  SelectOption as PfSelectOption,
 17	  type SelectProps as PfSelectProps,
 18	} from '@patternfly/react-core';
 19	import { useForkliftTranslation } from '@utils/i18n';
 20	
 21	type SelectOption = {
 22	  key?: number | string;
 23	  value: string;
 24	  label: string;
 25	  description?: string;
 26	  disabled?: boolean;
 27	};
 28	
 29	type SelectProps = Pick<PfSelectProps, 'onSelect' | 'className' | 'children'> & {
 30	  id: string;
 31	  value: string;
 32	  options?: SelectOption[];
 33	  status?: MenuToggleStatus;
 34	  placeholder?: string;
 35	  isDisabled?: boolean;
 36	  testId?: string;
 37	};
 38	
 39	/**
 40	 * A customized PatternFly Select that enforces project conventions.
 41	 *
 42	 * Use this instead of `@patternfly/react-core/Select`.
 43	 */
 44	const Select = (
 45	  {
 46	    children,
 47	    className,
 48	    id,
 49	    isDisabled,
 50	    onSelect,
 51	    options,
 52	    placeholder = '',
 53	    status,
 54	    testId,
 55	    value,
 56	  }: SelectProps,
 57	  ref: ForwardedRef<HTMLButtonElement>,
 58	) => {
 59	  const { t } = useForkliftTranslation();
 60	  const [isOpen, setIsOpen] = useState(false);
 61	  const toggleRef = useRef<HTMLButtonElement>();
 62	
 63	  useImperativeHandle(ref, () => toggleRef.current!);
 64	
 65	  const selectedOption = useMemo(
 66	    () =>
 67	      options?.find((option) => option.value === value) ??
 68	      // Try to find a label from custom children
 69	      (typeof value === 'string' ? { label: value } : undefined),
 70	    [options, value],
 71	  );
 72	
 73	  return (
 74	    <PfSelect
 75	      isScrollable
 76	      shouldFocusToggleOnSelect
 77	      id={id}
 78	      isOpen={isOpen}
 79	      selected={value}
 80	      className={className}
 81	      toggle={(pfToggleRef: MutableRefObject<HTMLButtonElement>) => (
 82	        <MenuToggle
 83	          isFullWidth
 84	          ref={(element: HTMLButtonElement) => {
 85	            if (pfToggleRef) {
 86	              pfToggleRef.current = element;
 87	            }
 88	
 89	            toggleRef.current = element;
 90	          }}
 91	          data-testid={testId}
 92	          isDisabled={isDisabled}
 93	          isExpanded={isOpen}
 94	          onClick={() => {
 95	            setIsOpen(!isOpen);
 96	          }}
 97	          aria-label="Select menu toggle"
 98	          status={status}
 99	        >
100	          {selectedOption?.label?.trim()
101	            ? selectedOption.label
102	            : (placeholder ?? t('Select an option'))}
103	        </MenuToggle>
104	      )}
105	      onOpenChange={(changedIsOpen) => {
106	        setIsOpen(changedIsOpen);
107	      }}
108	      onSelect={(event, selectedValue) => {
109	        onSelect?.(event, selectedValue);
110	        setIsOpen(false);
111	      }}
112	    >
113	      {children ?? (
114	        <SelectList>
115	          {(options ?? []).map((option) => (
116	            <PfSelectOption
117	              key={option.key ?? option.value}
118	              value={option.value}
119	              isDisabled={option.disabled}
120	              description={option.description}
121	            >
122	              {option.label}
123	            </PfSelectOption>
124	          ))}
125	        </SelectList>
126	      )}
127	    </PfSelect>
128	  );
129	};
130	
131	export default forwardRef(Select);

